import pytest
from functools import partial as functools_partial

def test_partial_happy_path():
    """Test basic functionality with positional and keyword arguments."""
    def add(a, b, c=0):
        return a + b + c

    # Partial with positional args
    add_partial = partial(add, 1, 2)
    assert add_partial() == 3
    assert add_partial(c=5) == 8

    # Partial with keyword args
    add_partial2 = partial(add, c=10)
    assert add_partial2(1, 2) == 13

    # Partial with both
    add_partial3 = partial(add, 1, c=5)
    assert add_partial3(2) == 8
    assert add_partial3(2, c=10) == 13  # Override partial kwarg

def test_partial_no_args():
    """Test partial with no arguments."""
    def greet():
        return "Hello"

    greet_partial = partial(greet)
    assert greet_partial() == "Hello"

def test_partial_with_only_kwargs():
    """Test partial with only keyword arguments."""
    def configure(a=1, b=2, c=3):
        return (a, b, c)

    config_partial = partial(configure, b=20, c=30)
    assert config_partial() == (1, 20, 30)
    assert config_partial(a=10) == (10, 20, 30)

