    """Test that wrapper kwargs override partial kwargs."""
    def func(a=1, b=2):
        return {'a': a, 'b': b}

    func_partial = partial(func, a=10, b=20)
    assert func_partial() == {'a': 10, 'b': 20}
    assert func_partial(a=100) == {'a': 100, 'b': 20}
    assert func_partial(b=200) == {'a': 10, 'b': 200}
    assert func_partial(a=100, b=200) == {'a': 100, 'b': 200}

